                new("O propilenoglicol em formulações semissólidas serve como:", new[]{"Espessante","Cossolvente e umectante","Corante","Antioxidante"}, 1, "O propilenoglicol é cossolvente (melhora solubilidade) e umectante (evita ressecamento).", "Médio"),
                new("A estabilidade de uma emulsão é favorecida por:", new[]{"Grandes gotas da fase dispersa","Diferença de densidade entre as fases","Viscosidade alta da fase contínua e emulsificante adequado","Ausência de tensoativo"}, 2, "Viscosidade alta da fase contínua retarda a coalescência, e o emulsificante forma filme protetor nas gotas.", "Médio"),
