                new("A Tween 80 (polissorbato 80) é um tensoativo:", new[]{"Aniônico","Catiônico","Não iônico","Anfotérico"}, 2, "Tween 80 (polissorbato 80) é tensoativo não iônico amplamente usado como emulsificante e solubilizante.", "Médio"),
                new("A diferença entre gel hidrofílico e gel lipofílico é:", new[]{"Apenas o custo","O tipo de base: aquosa vs. oleosa","O gel lipofílico é sempre estéril","Não há diferença"}, 1, "Gel hidrofílico usa base aquosa (ex: Carbopol); gel lipofílico (oleogel) usa base oleosa (ex: parafina com polietileno).", "Médio"),
