                new("A compressão direta tem como vantagem principal:", new[]{"Necessitar de granulação prévia","Menor número de etapas (sem granulação)","Exigir mais excipientes","Ser mais lenta"}, 1, "A compressão direta elimina etapas de granulação e secagem, sendo mais simples, rápida e econômica.", "Fácil"),
                new("O equipamento utilizado para revestimento de comprimidos é:", new[]{"Liofilizador","Drageadeira (coating pan) ou leito fluidizado","Autoclave","Centrífuga"}, 1, "Drageadeiras convencionais e de perfuração lateral, além de Wurster (leito fluidizado) para revestimento pelicular.", "Médio"),
